import{V as r}from"./chunks/theme.oEt1U0RI.js";import{c as a,o,G as n,ai as s,k as i}from"./chunks/framework.DPa1kTor.js";const g=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"software/open-ms.md","filePath":"software/open-ms.md"}'),l={name:"software/open-ms.md"},h=Object.assign(l,{setup(p){const t={light:"/images/software/OpenMS_transparent_blackFont.svg",dark:"/images/software/OpenMS_transparent_whiteFont.svg"};return(d,e)=>(o(),a("div",null,[n(i(r),{image:t,width:"30%"}),e[0]||(e[0]=s('<p><a href="https://www.openms.de" target="_blank" rel="noreferrer">OpenMS</a> is a powerful open-source software platform for analyzing mass spectrometry (MS) data. Actively developed for over two decades, it enables reproducible workflows across diverse applications such as:</p><ul><li>Bottom-up and top-down proteomics</li><li>Metabolomics</li><li>Structural biology</li><li>Oligonucleotide MS</li></ul><p>With a rich library of algorithms and tools, OpenMS supports both experimental researchers and developers.</p><ul><li><strong>Ready-to-use workflows</strong> (e.g. <a href="https://openms.readthedocs.io/en/latest/getting-started/webapps.html" target="_blank" rel="noreferrer">OpenMS WebApps</a>) simplify data analysis.</li><li><strong>Customizable modules</strong> in C++ and Python (<a href="https://pyopenms.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">pyOpenMS</a>) enable tailored solutions and seamless integration with machine learning, visualization, and statistical pipelines.</li></ul><hr><h2 id="deployment-options" tabindex="-1">Deployment Options <a class="header-anchor" href="#deployment-options" aria-label="Permalink to &quot;Deployment Options&quot;">​</a></h2><p>OpenMS can be deployed in many ways:</p><ul><li><strong>Interactive use</strong> - graphical user interface and command-line tools</li><li><strong>Custom scripting</strong> - Python (<a href="https://pyopenms.readthedocs.io/en/latest/" target="_blank" rel="noreferrer">pyOpenMS</a>) for rapid prototyping and integration with data science libraries</li><li><strong>Workflow systems</strong> - integration with <a href="https://www.nextflow.io/" target="_blank" rel="noreferrer">Nextflow</a>, <a href="https://snakemake.readthedocs.io/" target="_blank" rel="noreferrer">Snakemake</a>, and <a href="https://www.knime.com/" target="_blank" rel="noreferrer">KNIME</a></li><li><strong>Scalable environments</strong> - optimized for desktop use, HPC clusters, and cloud deployments</li></ul><hr><h2 id="key-features" tabindex="-1">Key Features <a class="header-anchor" href="#key-features" aria-label="Permalink to &quot;Key Features&quot;">​</a></h2><p>OpenMS is:</p><ul><li><strong>Open and interoperable</strong> - using HUPO-PSI open-standard file formats for maximum compatibility</li><li><strong>Accessible</strong> - with modern documentation and Python support</li><li><strong>Scalable</strong> - from single-PC use to cloud-based pipelines</li><li><strong>Community-driven</strong> - built by 150+ contributors worldwide, openly available on <a href="https://github.com/OpenMS/OpenMS" target="_blank" rel="noreferrer">GitHub</a> under a permissive BSD license</li></ul><hr><p>In short, <a href="https://www.openms.de" target="_blank" rel="noreferrer">OpenMS</a> empowers researchers to perform cutting-edge, reproducible MS data analysis - from individual experiments to large-scale, automated pipelines.</p>',14))]))}});export{g as __pageData,h as default};
